  1	import { type FC, useMemo, useRef } from 'react';
  2	import { useModal } from 'src/modules/Providers/modals/ModalHOC/useModal';
  3	
  4	import ProjectSelectEmptyState from '@components/common/ProjectSelect/ProjectSelectEmptyState';
  5	import type { ProjectSelectProps } from '@components/common/ProjectSelect/types';
  6	import TypeaheadSelect from '@components/common/TypeaheadSelect/TypeaheadSelect';
  7	import CreateProjectModal from '@components/modals/CreateProjectModal';
  8	import { type K8sResourceCommon, useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
  9	import { ProjectModel } from '@openshift-console/dynamic-plugin-sdk/lib/models';
 10	import { Button, ButtonVariant, Divider, Switch } from '@patternfly/react-core';
 11	import { PlusCircleIcon } from '@patternfly/react-icons';
 12	import { getName } from '@utils/crds/common/selectors';
 13	import { isEmpty } from '@utils/helpers';
 14	import { useForkliftTranslation } from '@utils/i18n';
 15	import { isSystemNamespace } from '@utils/namespaces';
 16	
 17	const showDefaultTargetsSwitchTestId = 'show-default-projects-switch';
 18	
 19	const ProjectSelectTypeAhead: FC<ProjectSelectProps> = ({
 20	  defaultProject,
 21	  emptyStateMessage,
 22	  id,
 23	  isDisabled = false,
 24	  noOptionsMessage,
 25	  onChange,
 26	  onNewValue,
 27	  placeholder,
 28	  projectNames,
 29	  setShowDefaultProjects,
 30	  showDefaultProjects,
 31	  testId = 'target-project-select',
 32	  toggleProps,
 33	  value,
 34	}) => {
 35	  const { t } = useForkliftTranslation();
 36	  const { showModal } = useModal();
 37	  const inputRef = useRef<HTMLInputElement | null>(null);
 38	  const [canCreate, loadingCreate] = useAccessReview({
 39	    group: ProjectModel.apiGroup,
 40	    resource: ProjectModel.plural,
 41	    verb: 'create',
 42	  });
 43	  const createAllowed = !loadingCreate && canCreate && Boolean(onNewValue);
 44	
 45	  const projectOptions = useMemo(() => {
 46	    if (!isEmpty(projectNames)) {
 47	      return projectNames
 48	        .filter(
 49	          (projectName) =>
 50	            showDefaultProjects || !isSystemNamespace(projectName) || projectName === value,
 51	        )
 52	        .map((projectName) => ({
 53	          content: projectName,
 54	          value: projectName,
 55	        }));
 56	    }
 57	    return defaultProject ? [{ content: defaultProject, value: defaultProject }] : [];
 58	  }, [projectNames, defaultProject, showDefaultProjects, value]);
 59	
 60	  const onProjectCreated = (newProject: K8sResourceCommon) => {
 61	    const projectName = getName(newProject);
 62	    if (onNewValue && projectName) {
 63	      onNewValue(projectName);
 64	    }
 65	  };
 66	
 67	  const onNewProject = () => {
 68	    showModal(<CreateProjectModal onCreated={onProjectCreated} />);
 69	  };
 70	
 71	  return (
 72	    <TypeaheadSelect
 73	      testId={testId}
 74	      ref={inputRef}
 75	      isScrollable
 76	      isDisabled={isDisabled}
 77	      allowClear
 78	      placeholder={placeholder ?? t('Select a project')}
 79	      id={id}
 80	      options={projectOptions}
 81	      defaultValue={defaultProject}
 82	      value={value ?? ''}
 83	      onChange={onChange}
 84	      footer={
 85	        createAllowed ? (
 86	          <Button
 87	            variant={ButtonVariant.link}
 88	            isInline
 89	            icon={<PlusCircleIcon />}
 90	            onClick={onNewProject}
 91	            data-testid="create-project-button"
 92	          >
 93	            {t('Create project')}
 94	          </Button>
 95	        ) : undefined
 96	      }
 97	      noOptionsMessage={noOptionsMessage}
 98	      toggleProps={toggleProps}
 99	      emptyState={
100	        emptyStateMessage ? (
101	          <ProjectSelectEmptyState
102	            emptyStateMessage={emptyStateMessage}
103	            onCreate={createAllowed ? onNewProject : undefined}
104	          />
105	        ) : null
106	      }
107	      filterControls={
108	        <>
109	          <div className="pf-v6-u-px-md pf-v6-u-py-md">
110	            <Switch
111	              id={showDefaultTargetsSwitchTestId}
112	              data-testid={showDefaultTargetsSwitchTestId}
113	              label={t('Show default projects')}
114	              isChecked={showDefaultProjects}
115	              onChange={(_event, checked) => {
116	                setShowDefaultProjects(checked);
117	                // Delay here so that the list is repopulated before attempting to re-focus
118	                setTimeout(() => inputRef.current?.focus(), 500);
119	              }}
120	            />
121	          </div>
122	          <Divider />
123	        </>
124	      }
125	    />
126	  );
127	};
128	
129	export default ProjectSelectTypeAhead;

